window.__QUIZ_DATA__=[{"id":"theory>Mathematics>2022>1>a","subject":"Mathematics","year":"2022","type":"Theory","sub_label":"a","group":"","topic":"ALGEBRAIC PROCESSES : SEQUENCE AND SERIES","question":"Give that (7 - 2x), 9, (5x + 17) are consecutive terms of a geometric progression (G. P) with common ratio, r > 0, find the values of x.","images":[],"marking_scheme":"r=U2U1=U3U2  U1 = 7 - 2x , U2 = 9,  U3 = 5x + 17  97-2x=5x+179    (7 - 2x)(5x + 17) = 81  35x + 119 - 10x2 - 34x = 81  -10x2 + x + 38 = 0  divide theought by 10  -x2 + 0.1x + 3.8 = 0  using quadratic formula  x=\u2212b\u00b1\u221a(b2\u22124ac)2a  a = -1, b = 0.1, c = 3.8  x=\u22120.1\u00b1\u221a(0.12\u22124(-1)(3.8))2(-1)  x=\u22120.1\u00b1\u221a(0.01+15.2)-2  x=\u22120.1\u00b1\u221a(15.21)-2  x=\u22120.1\u00b13.9-2  x=\u22120.1+3.9-2or\u22120.1-3.9-2  x = \u22121.9 or  2","marks":"5","difficulty":"3"},{"id":"theory>Mathematics>2022>1>b","subject":"Mathematics","year":"2022","type":"Theory","sub_label":"b","group":"FINAL","topic":"NUMBER AND NUMERATION : RATIO, PROPORTIONS AND RATES","question":"Two positive numbers are in the ratio 3:4. The sum of thrice the first number and twice the second number is 68. Find the smaller number.","images":[],"marking_scheme":"Let the numbers be x and y.  x:y = 3:4  xy=34  4x = 3y ----equation1  3x + 2y = 68 ----equation2  fromequation1,x=3y4  sub for x equation2   3(3y)4+2y=68  9y4+2y=68  multiply through by 4  9y + 8y = 272  17y = 272  y = 272/17  y = 16  x=3y4  x=3(16)4  x =12  the smaller number is 12","marks":"3","difficulty":"2"},{"id":"theory>Mathematics>2022>2>a","subject":"Mathematics","year":"2022","type":"Theory","sub_label":"a","group":"","topic":"ALGEBRAIC PROCESSES : CHANGE OF SUBJECT OF A FORMULA/RELATION","question":"Given that y = (pr/m -p2r)-3/2    make r the subject;","images":[],"marking_scheme":"multiply both sides by the power of -2/3    y-2/3 = (pr/m -p2r)-3/2(-2/3)    y-2/3 = (pr/m -p2r)  y-2/3 = r(p/m -p2)    r = y-2/3/(p/m-p2)","marks":"5","difficulty":"3"},{"id":"theory>Mathematics>2022>2>b","subject":"Mathematics","year":"2022","type":"Theory","sub_label":"b","group":"","topic":"ALGEBRAIC PROCESSES : FORMULATION AND EVALUATION OF ALGEBRAIC PROCESSES","question":"Given that y = (pr/m -p2r)-3/2find the value of r when y = -8, m = 1 and p =3","images":[],"marking_scheme":"r = y-2/3/(p/m-p2)    r = (-8)-2/3/(3/1-32)    r = (-23)-2/3/(3-32)    r = (-2)-2/(3-9)    r=14(-6)  r = 0.25/-6  r=-124","marks":"3","difficulty":"3"},{"id":"theory>Mathematics>2022>3","subject":"Mathematics","year":"2022","type":"Theory","sub_label":"3","group":"FINAL","topic":"MENSURATION : LENGTHS AND PERIMETERS","question":"A chord subtends an angle of 72\u2218 at the centre of circle of radius 24.5m. Calculate the perimeter of the minor segment. [Take \u03c0 = 22/7]","images":["data:image/png;base64,","data:image/png;base64,"],"marking_scheme":"perimeter of the minor segment AB =  length of arc AB + length of chord AB  lengthofarcAB=\u03b8360\u00d72\u03c0r   L.ofarc=72360\u00d72\u00d7227\u00d724.5  L. of arc = 30.8m    length of chord AB = 2CB   sin36=CB24.5   from trigonometryratio,sine\u03b8=opphyp  CB = 24.5 \u00d7 sin36  CB = 24.5 \u00d7 0.5878  CB = 14.4  chord AB = 2 \u00d7 CB = 2 \u00d7 14.4  chord AB = 28.8m  segment AB = chord AB + arc AB  segment AB = 28.8m + 30.8m  segment AB = 59.6m","marks":"8","difficulty":"3"},{"id":"theory>Mathematics>2022>4>a","subject":"Mathematics","year":"2022","type":"Theory","sub_label":"a","group":"FINAL","topic":"PLANE GEOMETRY : ANGLES","question":"In the diagram, BCDE is a circle with centre A. \u2220BCD = (2X+40)\u2218, \u2220BAD =(5X - 35)\u2218, \u2220BED =(2y + 10)\u2218 and \u2220ADC = 40\u2218. Find;        the values of x and y.","images":["data:image/png;base64,"],"marking_scheme":"5x - 35 = 2(2y + 10) (angle subtended by an arc at the centre of a circle = 2 times the angle subtended at any point on the circumference by same arc.  5x - 4y = 55  ------equation1  (2y + 10) + (2x + 40) = 180 (opposite angles in a cyclic quadrilateral are supplementary)  2x + 2y = 130 -----equation2  multiply equation2 by 2 and equation1 by 1  5x - 4y = 55  ------equation3  4x + 4y = 260 -----equation4  add equation3 and (4)  9x = 315  x = 315/9  x = 35  substitute for x in equation1  5x - 4y = 55  5(35) - 4y = 55  175 - 4y = 55  4y = 175 - 55  4y = 120  y = 30","marks":"5","difficulty":"2"},{"id":"theory>Mathematics>2022>4>b","subject":"Mathematics","year":"2022","type":"Theory","sub_label":"b","group":"FINAL","topic":"PLANE GEOMETRY : CIRCLES","question":"In the diagram, BCDE is a circle with centre A. \u2220BCD = (2X+40)\u2218, \u2220BAD =(5X - 35)\u2218, \u2220BED =(2y + 10)\u2218 and \u2220ADC = 40\u2218. Find;  \u2220ABC","images":["data:image/png;base64,"],"marking_scheme":"\u2220BAD = 5(35) -35 = 140\u2218  \u2220BCD = 2(35) + 40 = 110\u2218  \u2220ABC + \u2220BAD + 40 + \u2220BCD = 360 (sum of angles in a quadrilateral)  \u2220ABC + 140 + 40 + 110 = 360  \u2220ABC + 290 = 360  \u2220ABC = 360 -290  \u2220ABC = 70\u2218","marks":"3","difficulty":"3"},{"id":"theory>Mathematics>2022>5>a","subject":"Mathematics","year":"2022","type":"Theory","sub_label":"a","group":"","topic":"TRIGONOMETRY : SINE, COSINE AND TANGENT OF AN ANGLE","question":"Given that m = tan30\u2218 and n = tan45\u2218, simplify, without using calculator, m-nmn leaving the answer in the form p + \u221aq.","images":[],"marking_scheme":"from special angles   30\u2218 45\u2218 60\u2218sin 1/2 \u221a2/2 \u221a3/2cos \u221a3/2 \u221a2/2 1/2tan \u221a3/3 1 \u221a3  tan 30\u2218 = \u221a3/3, tan 45\u2218 = 1  m = \u221a3/3, n =1    m-n/mn = \u221a3/3 - 1/(\u221a3/3\u00d71)    m-n/mn = \u221a3/3 - 1 / \u221a3/3    m-n/mn = \u221a3-3/3 / \u221a3/3    m-nmn=\u221a3-33\u00d73\u221a3  m-nmn=\u221a3-3\u221a3  multiplyR.H.Sby\u221a3\u221a3  m-nmn=(\u221a3-3)\u221a33  m-nmn=3-3(\u221a3)3  m-nmn=33-3(\u221a3)3  m-nmn=1-\u221a3","marks":"5","difficulty":"2"},{"id":"theory>Mathematics>2022>5>b","subject":"Mathematics","year":"2022","type":"Theory","sub_label":"b","group":"FINAL","topic":"STATISTICS AND PROBABILITY. : PROBABILITY","question":"There are 20 women in a bus. 15 of them wear glasses and 10 wear wrist watches. If a woman is chosen at random from the bus, find the probability that she wears both glasses and wrist watch.","images":["data:image/png;base64,"],"marking_scheme":"\u03be = 20, let G = number of women that wear glasses and W = those that wear wrist watches while x wear both.   from the venn diagram   (15-x) + (10-x) + x = 20  25 -2x + x = 20  25 -x = 20   x = 25 - 20  x = 5  5 women wear both.  the probality that a woman wears both is x/20  p(x)=520  p(x)=14  p(x) = 0.25","marks":"3","difficulty":"2"},{"id":"theory>Mathematics>2022>6>a","subject":"Mathematics","year":"2022","type":"Theory","sub_label":"a","group":"","topic":"ALGEBRAIC PROCESSES : GRAPHS OF LINEAR AND QUADRATIC FUNCTIONS","question":"The graph shows the relation of the form y = mx2 + nx + r, where m, n and r are constants.  Using the graph:    state the scale used on both axes;","images":["data:image/jpeg;base64,"],"marking_scheme":"On x-axis, 2cm = 2units  On y-axis, 2cm = 10units","marks":"2","difficulty":"3"},{"id":"theory>Mathematics>2022>6>b","subject":"Mathematics","year":"2022","type":"Theory","sub_label":"b","group":"","topic":"ALGEBRAIC PROCESSES : GRAPHS OF LINEAR AND QUADRATIC FUNCTIONS","question":"The graph shows the relation of the form y = mx2 + nx + r, where m, n and r are constants.  Using the graph:find the values of m,n and r.","images":["data:image/jpeg;base64,"],"marking_scheme":"Points on line PQ are (-5,-27) and (3,5)  The equation of line PQ is y = mx + c  m=5-(-27)3-(-5)=328=4  c is the y-intercept = -7  y = 4x - 7  the solution of the quadratic curve is -2 and 4  x = -2 or x = 4  sum of roots = -2+ 4 = 2  product of roots = -2 \u00d7 4 = -8  recall that x2 - (sum of roots)x + product of roots = 0  x2 - (2)x + (-8) = 0  -x2 + 2x + 8 = 0 (according to the graph coefficient of a is negative)  -x2 + 2x + 8 = 0 ----equation1  y - 4x + 7 = 0 -------equation2  equation1 = equation2  -x2 + 2x + 8 = y - 4x + 7  collecting like terms  y = -x2 +2x + 4x +8 - 7   y = -x2 + 6x - 1  comparing with y = mx2 + nx + r  m = -1, n = 6 and r = -1","marks":"2","difficulty":"3"},{"id":"theory>Mathematics>2022>6>c","subject":"Mathematics","year":"2022","type":"Theory","sub_label":"c","group":"FINAL","topic":"ALGEBRAIC PROCESSES : DRAWING TANGENTS TO CURVES TO DETERMINE THE GRADIENT AT A GIVEN POINT","question":"The graph shows the relation of the form y = mx2 + nx + r, where m, n and r are constants.  Using the graph:Find the gradient of the line through P and Q","images":["data:image/jpeg;base64,"],"marking_scheme":"Gradient=y2-y1x2-x1  P(-5,-27), Q(3,5)  y1 = -27. y2 = 5, x1 = -5, x2 = 3  m=5-(-27)3-(-5)=5+273+5=328  m = 4","marks":"2","difficulty":"3"},{"id":"theory>Mathematics>2022>6>d","subject":"Mathematics","year":"2022","type":"Theory","sub_label":"d","group":"","topic":"ALGEBRAIC PROCESSES : GRAPHS OF LINEAR AND QUADRATIC FUNCTIONS","question":"The graph shows the relation of the form y = mx2 + nx + r, where m, n and r are constants.  Using the graph:State the range of values of x for which y > 0.","images":["data:image/jpeg;base64,"],"marking_scheme":"-2 \u2264 x \u2264 4","marks":"1.5","difficulty":"2"},{"id":"theory>Mathematics>2022>7>a","subject":"Mathematics","year":"2022","type":"Theory","sub_label":"a","group":"FINAL","topic":"NUMBER AND NUMERATION : PROFIT AND LOSS","question":"A man purchased 180 copies of a book at \u20a6250.00 each. He sold y copies at \u20a6300.00 each and the rest at a discount of 5kobo in the Naira of the cost price. If he made a profit of \u20a67,125.00, find the value of y.","images":[],"marking_scheme":"180 copies at \u20a6250 each, the total cost price (C.P) = 180 *times 250 = \u20a645000  profit = \u20a67,125  profit = selling price - cost price  S.P = profit + C.P  S.P= \u20a67,125 + 45,000 = \u20a652,125  y copies sold at \u20a6300, S.P for y copies = \u20a6300y and let the remaining copies be  180-y sold at \u20a6250 - \u20a60.05 = \u20a6249.95, S.P for remaining = \u20a6249.95(180-y)  300y + 249.95(180-y) = 52,125   300y + 44,991 - 249.95y = 52,125  300y - 249.95y = 52,125 - 44,991  50.05y = 7,134  y=713450.05  y = 142.54  y \u224c143","marks":"3","difficulty":"3"},{"id":"theory>Mathematics>2022>7>b>i","subject":"Mathematics","year":"2022","type":"Theory","sub_label":"i","group":"","topic":"ALGEBRAIC PROCESSES : FORMULATION AND EVALUATION OF ALGEBRAIC PROCESSES","question":"A trader bought x bags of rice at a cost, c = 24x + 103 and sold them at a price,   s=33x-x220    Find the expression for the profit.","images":[],"marking_scheme":"profit (p) = selling price (s) - cost price (c)  p=33x-x220-(24x+103)  p=33x-x220-24x-103  p=-x220+9x-103","marks":"3","difficulty":"3"},{"id":"theory>Mathematics>2022>7>b>ii","subject":"Mathematics","year":"2022","type":"Theory","sub_label":"ii","group":"FINAL","topic":"NUMBER AND NUMERATION : PERCENTAGES","question":"A trader bought x bags of rice at a cost, c = 24x + 103 and sold them at a price,   s=33x-x220If 20 bags of rice were sold, calculate the percentage profit.","images":[],"marking_scheme":"p=-x220+9x-103  c  = 24x + 103  x = 20  c = 24(20) + 103  c = 480 + 103  c = 583units  p=-20220+9(20)-103  p=-40020+180-103  p = -20 + 180 - 103  p = 180 - 123  p = 57units  percentageprofit=pc\u00d7100%  percentageprofit=57583\u00d7100%  percentage profit = 9.78%","marks":"1.5","difficulty":"3"},{"id":"theory>Mathematics>2022>8>a","subject":"Mathematics","year":"2022","type":"Theory","sub_label":"a","group":"FINAL","topic":"NUMBER AND NUMERATION : PERCENTAGES","question":"Item Food and drinks Fuel Rent Building project Education SavingsPercentage(%) 35 7.5 10 15 17.5 x  The table shows the monthly expenditure (in percentage) of Mr. Okafor's salary.    Calculate the percentage of Mr. Okafor's salary that was put into savings.","images":[],"marking_scheme":"total percentage = 100  i.e 35 + 7.5 + 10 + 15 + 17.5 + x = 100  85 + x = 100  x = 100 - 85  x = 15  15% was put into savings","marks":"2","difficulty":"1"},{"id":"theory>Mathematics>2022>8>b","subject":"Mathematics","year":"2022","type":"Theory","sub_label":"b","group":"","topic":"STATISTICS AND PROBABILITY. : STATISTICS","question":"Item Food and drinks Fuel Rent Building project Education SavingsPercentage(%) 35 7.5 10 15 17.5 x  The table shows the monthly expenditure (in percentage) of Mr. Okafor's salary.illustrate the information on a pie chart.","images":["data:image/jpeg;base64,"],"marking_scheme":"Food and drinks = 35/100 \u00d7 360\u2218 = 126\u2218  Fuel = 7.5/100 \u00d7 360\u2218 = 27\u2218  Rent = 10/100 \u00d7 360\u2218 = 36\u2218  Building Projects = 15/100 \u00d7 360\u2218 = 54\u2218  Education = 17.5/100 \u00d7 360\u2218 = 63\u2218  Savings = 15/100 \u00d7 360\u2218 = 54\u2218","marks":"2","difficulty":"2"},{"id":"theory>Mathematics>2022>8>c>i","subject":"Mathematics","year":"2022","type":"Theory","sub_label":"i","group":"FINAL","topic":"NUMBER AND NUMERATION : PERCENTAGES","question":"Item Food and drinks Fuel Rent Building project Education SavingsPercentage(%) 35 7.5 10 15 17.5 x  The table shows the monthly expenditure (in percentage) of Mr. Okafor's salary.If Mr. Okafor's annual gross salary is $28,800.00 and he pays tax of 12%, calculate :  his monthly tax","images":[],"marking_scheme":"tax = 12% of the gross salary  tax=12100\u00d728,800  tax = $3456  monthlytax=tax12  monthlytax=345612  monthly tax = $288","marks":"2","difficulty":"2"},{"id":"theory>Mathematics>2022>8>c>ii","subject":"Mathematics","year":"2022","type":"Theory","sub_label":"ii","group":"FINAL","topic":"NUMBER AND NUMERATION : PERCENTAGES","question":"Item Food and drinks Fuel Rent Building project Education SavingsPercentage(%) 35 7.5 10 15 17.5 x  The table shows the monthly expenditure (in percentage) of Mr. Okafor's salary.If Mr. Okafor's annual gross salary is $28,800.00 and he pays tax of 12%, calculate :  amount saved each month","images":[],"marking_scheme":"monthlygrosssalary=$2880012                                         = $2400  monthly tax = $288  net income = gross salary - tax  net income = $2400 - $288  net income = $2112  his expenses are based on the net income.  he saved 15% each month   15100\u00d72112  31680100  $316.8  he saved $316.8 each month.","marks":"1.5","difficulty":"2"},{"id":"theory>Mathematics>2022>9>a","subject":"Mathematics","year":"2022","type":"Theory","sub_label":"a","group":"","topic":"TRIGONOMETRY : GRAPHS OF SINE AND COSINE","question":"Copy and complete the table of values for y = 3sinx + 7cosx for 0\u2218\u2264x\u2264180\u2218.  x 0\u2218 20\u2218 40\u2218 60\u221880\u2218100\u2218 120\u2218 140\u2218 160\u2218 180\u2218y7.0   4.2 -0.9","images":[],"marking_scheme":"when x = 20\u2218  y = 3sin20\u2218 + 7cos20\u2218  y = 1.0261 + 6.5778  y = 7.6039  when x = 40\u2218  y = 3sin40\u2218 + 7cos40\u2218  y = 1.9284 + 5.3623  y = 7.2907  when x = 60\u2218  y = 3sin60\u2218 + 7cos60\u2218  y = 2.5981 + 3.5  y = 6.0981  when x = 100\u2218  y = 3sin100\u2218 + 7cos100\u2218  y = 2.9544 - 1.2155  y = 1.7389  when x = 140\u2218  y = 3sin140\u2218 + 7cos140\u2218  y = 1.9284 - 5.3623  y = -3.4339  when x = 160\u2218  y = 3sin160\u2218 + 7cos160\u2218  y = 1.0261 - 6.5778  y = -5.5517  when x = 180\u2218  y = 3sin180\u2218 + 7cos180\u2218  y = 0 - 7   y = -7  x 0\u2218 20\u2218 40\u2218 60\u221880\u2218100\u2218 120\u2218 140\u2218 160\u2218 180\u2218y7.07.67.36.14.21.7-0.9-3.4-5.6-7.0","marks":"2","difficulty":"2"},{"id":"theory>Mathematics>2022>9>b","subject":"Mathematics","year":"2022","type":"Theory","sub_label":"b","group":"","topic":"TRIGONOMETRY : GRAPHS OF SINE AND COSINE","question":"Using a scale of 2cm to 20\u2218 on the x-axis and 2cm to 2 units on the y-axis, draw the graph of y = 3sinx + 7cosx for 0\u2264x\u2264180\u2218.","images":["data:image/jpeg;base64,"],"marking_scheme":"","marks":"2","difficulty":"3"},{"id":"theory>Mathematics>2022>9>c>i","subject":"Mathematics","year":"2022","type":"Theory","sub_label":"i","group":"","topic":"ALGEBRAIC PROCESSES : GRAPHS OF LINEAR AND QUADRATIC FUNCTIONS","question":"Using the graph, find the;    value of y when x = 150\u2218;","images":["data:image/jpeg;base64,"],"marking_scheme":"From the graph, x = 150\u2218 at point P and corresponding y value is -4.6","marks":"2","difficulty":"2"},{"id":"theory>Mathematics>2022>9>c>ii","subject":"Mathematics","year":"2022","type":"Theory","sub_label":"ii","group":"","topic":"ALGEBRAIC PROCESSES : LINEAR INEQUALITIES","question":"Using the graph, find the;range of values of x for which y > 0.","images":[],"marking_scheme":"0 \u2264 x \u2264 113\u2218","marks":"1.5","difficulty":"2"},{"id":"theory>Mathematics>2022>10>a","subject":"Mathematics","year":"2022","type":"Theory","sub_label":"a","group":"FINAL","topic":"STATISTICS AND PROBABILITY. : STATISTICS","question":"Age(years) 3 4 5 6 7 8 9 10Number of Children 2 6 5 x 6 9 8 5  The table shows the distribution of ages of a number of children in a school. If the mean of the distribution is 7, find the;    value of x","images":[],"marking_scheme":"x f fx3 2 64 6 245 5 256 x 6x7 6 428 9 729 8 7210 5 50  \u2211f =41+x \u2211fx=291+6x  mean=\u2211fx\u2211f=7  291+6x41+x=7   7(41+x) = 291+6x  287 + 7x = 291 + 6x  7x - 6x = 291 - 287  x = 4.","marks":"4","difficulty":"3"},{"id":"theory>Mathematics>2022>10>b","subject":"Mathematics","year":"2022","type":"Theory","sub_label":"b","group":"FINAL","topic":"STATISTICS AND PROBABILITY. : STATISTICS","question":"Age(years) 3 4 5 6 7 8 9 10Number of Children 2 6 5 x 6 9 8 5  The table shows the distribution of ages of a number of children in a school. If the mean of the distribution is 7, find the;standard deviation of their ages.","images":[],"marking_scheme":"x f x-\u03bc (x-\u03bc)2 f(x-\u03bc)23 2 -4 16 324 6 -3 9 545 5 -2 4 206 4 -1 1 47 6 0 0 08 9 1 1 99 8 2 4 3210 5 3 9 45  \u2211f =45   \u2211f(x-\u03bc)2=196    standarddeviation(\u03c3)=\u221a(\u2211f(x-\u03bc)2\u2211f)  \u03c3=\u221a19645  \u03c3 = \u221a 4.3556  \u03c3 = 2.09","marks":"3.5","difficulty":"3"},{"id":"theory>Mathematics>2022>11>a","subject":"Mathematics","year":"2022","type":"Theory","sub_label":"a","group":"FINAL","topic":"PLANE GEOMETRY : ANGLES","question":"The exterior angles of a polygon are 42\u2218, 38\u2218, 57\u2218, x\u2218, (x+y)\u2218, (2x-15)\u2218 and (3x-y)\u2218. If x is 7\u2218 less than y, find the values of x and y.","images":[],"marking_scheme":"The sum of exterior angles in a polygon is 360\u2218.  x = y - 7\u2218 -------equation1  42\u2218 + 38\u2218 + 57\u2218 + x\u2218 + (x+y)\u2218 + (2x-15)\u2218 + (3x-y)\u2218 =  360\u2218  replace x by y -7  42\u2218 + 38\u2218 + 57\u2218 + (y-7)\u2218 + (y-7+y)\u2218 + (2(y-7)-15)\u2218 + (3(y-7)-y)\u2218 =  360\u2218  137\u2218 + (y-7)\u2218 + (y-7+y)\u2218 + (2(y-7)-15)\u2218 + (3(y-7)-y)\u2218 = 360\u2218  137\u2218 + (3y -14)\u2218 + (2y-14-15)\u2218 + (2y-21)\u2218 = 360\u2218  (7y)\u2218 + 73\u2218 = 360\u2218  7y\u2218 = 360\u2218 - 73\u2218  7y\u2218 = 287\u2218  y=2877  y = 41\u2218  from equation1  x = y - 7\u2218  x = 41 - 7  x = 34\u2218","marks":"5","difficulty":"3"},{"id":"theory>Mathematics>2022>11>b","subject":"Mathematics","year":"2022","type":"Theory","sub_label":"b","group":"FINAL","topic":"PLANE GEOMETRY : CIRCLES","question":"In diagram, 0 is the centre of the circle XYZ, \u2220ZXO = 34\u2218 and \u2220XOY =146\u2218. Find \u2220OYZ","images":["data:image/png;base64,"],"marking_scheme":"Triangle X0Z and triangle YOZ are isosceles triangle since they are bounded by the radius of the circle.  therefore, \u2220ZXO = \u2220XZO = 34\u2218 and \u2220OYZ = \u2220OZY  \u2220XZY=\u2220XOY2(anglesubtendedatthecircumferenceofcirclefrombyanarcishalftheanglesubtendedatthecentreofthecirclebythesamearc)  \u2220XZY=1462  \u2220XZY = 73\u2218  \u2220OZY = \u2220XZY -\u2220XZO  \u2220OZY = (73 - 34)\u2218  \u2220OZY = 39\u2218  \u2220OYZ = \u2220OZY  \u2220OYZ = 39\u2218","marks":"2.5","difficulty":"2"},{"id":"theory>Mathematics>2022>12>a>i","subject":"Mathematics","year":"2022","type":"Theory","sub_label":"i","group":"FINAL","topic":"STATISTICS AND PROBABILITY. : PROBABILITY","question":"The probability that an athlete will not win any of the three races is 1/4.   If the athlete runs in all the races, what is the probability that the athlete will win;    only the second race","images":[],"marking_scheme":"The probability of not winning any of the 3 races = 1/4  let the probability of winning be p(A) = 1 - 1/4 = 3/4  If he won only the second, it means he lost the first and third race = p(\u223cA1) \u00d7 P(A2) \u00d7 P(\u223cA3)  p(\u223cA1\u2229A2\u2229\u223cA3)=14\u00d734\u00d714  p(\u223cA1\u2229A2\u2229\u223cA3)=364","marks":"2","difficulty":"2"},{"id":"theory>Mathematics>2022>12>a>ii","subject":"Mathematics","year":"2022","type":"Theory","sub_label":"ii","group":"FINAL","topic":"STATISTICS AND PROBABILITY. : PROBABILITY","question":"The probability that an athlete will not win any of the three races is 1/4.   If the athlete runs in all the races, what is the probability that the athlete will win;all the three races;","images":[],"marking_scheme":"p(A1\u2229A2\u2229A3)=34\u00d734\u00d734  p(A1\u2229A2\u2229A3)=2764","marks":"2","difficulty":"2"},{"id":"theory>Mathematics>2022>12>a>iii","subject":"Mathematics","year":"2022","type":"Theory","sub_label":"iii","group":"FINAL","topic":"STATISTICS AND PROBABILITY. : PROBABILITY","question":"The probability that an athlete will not win any of the three races is 1/4.   If the athlete runs in all the races, what is the probability that the athlete will win;only two of the races?","images":[],"marking_scheme":"only two of the races is p(A1\u2229A2\u2229\u223dA3) or p(A1\u2229\u223dA2\u2229A3) or p(\u223dA1\u2229A2\u2229A3)   =(34\u00d734\u00d714)+(34\u00d714\u00d734)+(14\u00d734\u00d734)  =(964)+(964)+(964)   =2764","marks":"2","difficulty":"2"},{"id":"theory>Mathematics>2022>12>b","subject":"Mathematics","year":"2022","type":"Theory","sub_label":"b","group":"FINAL","topic":"MENSURATION : VOLUMES","question":"A cone with perpendicular height 24cm has a volume of 1200cm3. Find the volume of a cone with same base radius and height 84cm. [Take \u03c0 =22/7]","images":[],"marking_scheme":"V=13\u03c0r2h  the first cone has V = 1200cm3, h = 24cm  r=\u221a3V\u03c0h  r=\u221a3(1200)(7)22(24)  r=\u221a25200528  r = 6.91cm  both cones have same base radius  the second cone, h = 84cm, r = 6.91cm  V=13\u03c0r2h  V=13\u00d7227\u00d76.912\u00d784  V=88238.488821  V = 4201.83cm3","marks":"1.5","difficulty":"3"},{"id":"theory>Mathematics>2022>13>a","subject":"Mathematics","year":"2022","type":"Theory","sub_label":"a","group":"FINAL","topic":"MENSURATION : VOLUMES","question":"The diameter of a cylinder closed at both ends is 7cm. If the total surface area is 209cm2, calculate the height. [Take \u03c0 = 22/7]","images":[],"marking_scheme":"Total surface area of a cylinder (A) = 2\u03c0rh + 2\u03c0r2  A = 209cm2, d = 7cm, r = d/2 = 3.5cm  h=A-2\u03c0r22\u03c0r  h = ( 209-(2\u00d7 22/7 \u00d7 3.52) )/( 2 \u00d7 22/7 \u00d7 3.5 )  h=209-7722  h=13222  h = 6cm","marks":"4","difficulty":"2"},{"id":"theory>Mathematics>2022>13>b>i","subject":"Mathematics","year":"2022","type":"Theory","sub_label":"i","group":"","topic":"TRIGONOMETRY : ANGLES OF ELEVATION AND DEPRESSION","question":"The points X and Y, 19m apart are on the same side of a tree. The angles of elevation of the top, T, of the tree from X and Y on the horizontal ground with the foot of the tree are 43\u2218 and 38\u2218 respectively.    Illustrate the information in a diagram.","images":["data:image/png;base64,"],"marking_scheme":"","marks":"2","difficulty":"3"},{"id":"theory>Mathematics>2022>13>b>ii","subject":"Mathematics","year":"2022","type":"Theory","sub_label":"ii","group":"FINAL","topic":"TRIGONOMETRY : ANGLES OF ELEVATION AND DEPRESSION","question":"The points X and Y, 19m apart are on the same side of a tree. The angles of elevation of the top, T, of the tree from X and Y on the horizontal ground with the foot of the tree are 43\u2218 and 38\u2218 respectively.Find, correct to one decimal place, the height of the tree.","images":[],"marking_scheme":"tan\u03b8=oppadj(trigonometricratio)  for triangle TOX   tan43\u2218=TOXO letXO=x,TO=h  tan43\u2218=hx  h = xtan43\u2218  -------equation1  for triangle TOY  tan38\u2218=hYO,YO=19+x  tan38\u2218=h(19+x)  h = (19+x)tan38\u2218  -------equation2  solving equation (1) and (2)  xtan43\u2218 = (19+x)tan38\u2218  xtan43\u2218 = 19tan38\u2218 + xtan38\u2218  xtan43\u2218 - xtan38\u2218 = 19tan38\u2218  x(tan43\u2218 - tan38\u2218) = 19tan38\u2218  x(0.9325 - 0.7813) = 14.8444  0.1512x = 14.8444  x=14.84440.1512   x = 98.18m  from equation1, h = xtan43\u2218  h = 98.18tan43\u2218  h = 91.6m  the height of the tree is 91.6m","marks":"1.5","difficulty":"3"}];